Wrap list items in Dismissible widgets:

```dart
ListView.builder(
  itemBuilder: (context, index) {
    final contact = contacts[index];
    return Dismissible(
      key: Key(contact.id),
      background: _buildSwipeLeftBackground(), // Delete action
      secondaryBackground: _buildSwipeRightBackground(), // Edit action
      onDismissed: (direction) {
        if (direction == DismissDirection.startToEnd) {
          _deleteContact(contact);
        } else {
          _editContact(contact);
        }
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(content: Text('${contact.name} removed')),
        );
      },
      child: _buildContactTile(contact),
    );
  },
)

Widget _buildSwipeLeftBackground() {
  return Container(
    alignment: Alignment.centerRight,
    padding: EdgeInsets.only(right: 20),
    color: Colors.red,
    child: Icon(Icons.delete, color: Colors.white),
  );
}
```

