No icons in toasts. No action buttons (undo, retry, view). No persistent notifications for important alerts. No progress indicators for long-running operations. Error toasts just show text without visual emphasis. No custom styling or branding.

ui_ux_improvements.proposed_change:
Create enhanced toast system:

```dart
// lib/core/widgets/enhanced_toast.dart
class EnhancedToast {
  static void showSuccess(
    BuildContext context,
    String message, {
    VoidCallback? onAction,
    String? actionLabel,
  }) {
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Row(
          children: [
            Icon(Icons.check_circle, color: Colors.white),
            SizedBox(width: 12),
            Expanded(child: Text(message)),
          ],
        ),
        backgroundColor: Colors.green,
        action: onAction != null
            ? SnackBarAction(
                label: actionLabel ?? 'UNDO',
                textColor: Colors.white,
                onPressed: onAction,
              )
            : null,
        duration: Duration(seconds: 4),
      ),
    );
  }

  static void showProgress(
    BuildContext context,
    String message,
    Stream<double> progressStream,
  ) {
    final controller = ScaffoldMessenger.of(context);
    controller.showSnackBar(
      SnackBar(
        content: StreamBuilder<double>(
          stream: progressStream,
          builder: (context, snapshot) {
            return Column(
              mainAxisSize: MainAxisSize.min,
              children: [
                LinearProgressIndicator(value: snapshot.data),
                SizedBox(height: 8),
                Text(message),
              ],
            );
          },
        ),
        duration: Duration(minutes: 5), // Persistent
      ),
    );
  }

  static void showError(
    BuildContext context,
    String message, {
    VoidCallback? onRetry,
  }) {
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Row(
          children: [
            Icon(Icons.error, color: Colors.white),
            SizedBox(width: 12),
            Expanded(child: Text(message)),
          ],
        ),
        backgroundColor: Theme.of(context).colorScheme.error,
        action: onRetry != null
            ? SnackBarAction(
                label: 'RETRY',
                onPressed: onRetry,
              )
            : null,
        duration: Duration(seconds: 5),
      ),
    );
  }
}

// Usage
EnhancedToast.showSuccess(
  context,
  'Contact added successfully',
  onAction: () => _undoAddContact(),
  actionLabel: 'UNDO',
);
```
